from functools import wraps

def sade(func):
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@sade
def hesapla():
    return 42

print(hesapla.__name__)

def koru(func):
    @wraps(func)
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper

@koru
def hesapla():
    return 42

print(hesapla.__name__)

from functools import wraps

def tekrar(deneme):
    # decorator ve wrapper katmanlarını tamamla
    pass


@tekrar(3)
def pozitif_bol(a, b):
    if b <= 0:
        raise ValueError("Bölen pozitif olmalı.")
    return a / b


print(f"Başarılı: {pozitif_bol(24, 2):g}")

def olc(func):
    def wrapper(*args, **kwargs):
        return func(*args, **kwargs)
    return wrapper


@olc
def raporla(tutarlar):
    """Satış toplamını üretir."""
    return sum(tutarlar)


print(raporla.__name__)
print(raporla.__doc__)
print(raporla([50, 75]))

